try {
  const response = $json;
  const raw = response.candidates?.[0]?.content?.parts?.[0]?.text || '';
  let parsed = null;

  const attemptParse = (value) => {
    const trimmed = String(value || '').trim();
    const cleaned = trimmed.startsWith('```')
      ? trimmed.replace(/^```json/, '').replace(/^```/, '').replace(/```$/, '').trim()
      : trimmed;
    const start = cleaned.indexOf('{');
    const end = cleaned.lastIndexOf('}');
    const jsonText = start >= 0 && end > start ? cleaned.slice(start, end + 1) : cleaned;
    return JSON.parse(jsonText);
  };

  try {
    parsed = attemptParse(raw);
  } catch (firstError) {
    try {
      parsed = attemptParse(raw.replace(/\n/g, '\n'));
    } catch (secondError) {
      return [{ json: { parse_error: String(secondError), raw_judge_text: raw, judge_raw_response: response } }];
    }
  }

  console.log('[Code Parse Judge] weighted_total=' + (parsed.weighted_total || 'n/a') + ' failures=' + (parsed.top_failure_points || []).length);
  return [{ json: { judge: parsed, judge_raw_response: response } }];
} catch (error) {
  return [{ json: { parse_error: String(error), judge_raw_response: $json } }];
}

parameters.jsonBody:
={{ {
  system_instruction: {
    parts: [{
      text: `You are a prompt engineer specializing in voice AI agent optimization.

You will receive:
1. The current system prompt (version N)
2. The judge's evaluation with failure points and suggested fixes
3. PRIOR_CHANGELOG: history of what was changed in previous versions

Your job:
1. Apply ONLY the fixes the judge recommended — do not rewrite unrelated sections
2. Preserve everything that scored well (4-5) — explicitly listed in strengths_to_preserve
3. Add new objection handlers for identified gaps
4. Keep the total prompt under 600 tokens (voice latency constraint)

CRITICAL RULES (non-negotiable):
- NEVER remove or rewrite: the doctor list (Dr. Emily Chen, Dr. James Park, Dr. Priya Sharma, Dr. Marcus Webb), the show_confirmation tool trigger, the TURN-TAKING RULES section, the record_outcome end-of-call requirement, or the conversation-history guard ('NEVER re-ask information')
- NEVER re-add a fix that is already present in PRIOR_CHANGELOG — check before adding
- If regression_flags in the judge output is non-empty, prioritize fixing those dimensions
- Surgical edits only — do not restructure or reformat sections that are not broken
- Output the complete revised prompt
- Output a changelog: 3-5 bullets of what specifically changed and why

Output JSON ONLY with keys: revised_prompt (string), changelog (array of strings).`
    }]
  },
  contents: [{
    role: 'user',
    parts: [{
      text: `CURRENT PROMPT:
${$node['Code Prepare Inputs'].json.current_prompt}

JUDGE OUTPUT:
${JSON.stringify($json.judge || {}, null, 2)}

PRIOR_CHANGELOG (do not re-add these):
${($node['Code Prepare Inputs'].json.changelog_history || []).join('
')}`
    }]
  }]
} }}

parameters.jsCode:
try {
  const callPayload = $node['Code Prepare Inputs'].json.call || {};
  const judge = $node['Code Parse Judge'].json.judge || {};
  const currentPrompt = $node['Code Prepare Inputs'].json.current_prompt || '';
  const priorScores = $node['Code Prepare Inputs'].json.prior_scores || [];
  const reviserRaw = $json.candidates?.[0]?.content?.parts?.[0]?.text || '';

  let reviser = { revised_prompt: currentPrompt, changelog: ['No revision output parsed — preserved current prompt.'] };
  try {
    const start = reviserRaw.indexOf('{');
    const end = reviserRaw.lastIndexOf('}');
    const maybeJson = start >= 0 && end > start ? reviserRaw.slice(start, end + 1) : reviserRaw;
    reviser = JSON.parse(maybeJson);
  } catch (e) {
    reviser = { revised_prompt: reviserRaw || currentPrompt, changelog: ['Fallback parse path used.'] };
  }

  // ── GUARDRAIL: ensure critical sections are preserved ─────────────────────
  const REQUIRED_KEYS = [
    'Dr. Emily Chen', 'Dr. Marcus Webb',
    'show_confirmation',
    'TURN-TAKING RULES',
    'record_outcome',
    'NEVER re-ask'
  ];
  const revised = reviser.revised_prompt || '';
  const missing = REQUIRED_KEYS.filter(k => !revised.includes(k));
  if (missing.length > 0) {
    console.warn('[Code Format Outputs] GUARDRAIL triggered — missing sections:', missing.join(', '));
    const fixes = (judge.prompt_fix_suggestions || []).join('\n');
    reviser.revised_prompt = currentPrompt + (fixes ? '\n\nADDITIONAL INSTRUCTIONS:\n' + fixes : '');
    reviser.changelog = ['[GUARDRAIL] Preserved original prompt structure. Appended judge suggestions as addendum. Missing sections were: ' + missing.join(', ')];
  }

  // ── VERSION DERIVATION ────────────────────────────────────────────────────
  const inferredVersion = callPayload.prompt_version || 'v1';
  const vMatch = String(inferredVersion).match(/(\d+)/);
  const nextNum = vMatch ? parseInt(vMatch[1]) + 1 : 2;
  const currentVersion = inferredVersion;
  const nextVersion = 'v' + nextNum;
  console.log('[Code Format Outputs] version:', currentVersion, '\u2192', nextVersion);

  // ── REGRESSION DETECTION ─────────────────────────────────────────────────
  let regressionWarning = null;
  if (priorScores.length > 0) {
    const prevScore = priorScores[priorScores.length - 1]?.score;
    const currentScore = judge.weighted_total;
    if (prevScore != null && currentScore != null && currentScore < prevScore - 0.3) {
      regressionWarning = `Score dropped from ${prevScore.toFixed(2)} to ${currentScore.toFixed(2)} — investigate before next revision`;
      console.warn('[Code Format Outputs] REGRESSION:', regressionWarning);
    }
  }

  const analysisReport = {
    iteration: null,
    calls_analyzed: [callPayload.call_id || 'unknown_call'],
    prompt_version_evaluated: currentVersion,
    aggregate_scores: Object.assign({}, judge.scores || {}, { weighted_total: judge.weighted_total || null }),
    top_failure_points: judge.top_failure_points || [],
    regression_flags: judge.regression_flags || [],
    strengths_to_preserve: judge.strengths_to_preserve || [],
    prompt_changes: { from_version: currentVersion, to_version: nextVersion, changelog: reviser.changelog || [] },
    regression_warning: regressionWarning,
    timestamp: new Date().toISOString()
  };

  const promptVersion = {
    version: nextVersion,
    created_at: new Date().toISOString(),
    created_by: 'n8n_analysis_workflow',
    token_count: Math.ceil(String(reviser.revised_prompt || '').length / 4),
    changelog: Array.isArray(reviser.changelog) ? reviser.changelog.join(' | ') : String(reviser.changelog || ''),
    changelog_list: Array.isArray(reviser.changelog) ? reviser.changelog : [String(reviser.changelog || '')],
    prompt: reviser.revised_prompt || '',
    metadata: {
      avg_score_during_use: null,
      calls_made_with_this_version: 0,
      replaced_by: null,
      weighted_total_trigger: judge.weighted_total || null,
      guardrail_triggered: missing.length > 0,
      regression_warning: regressionWarning
    }
  };

  const callLog = Object.assign({}, callPayload, {
    judge_scores: judge.scores || {},
    weighted_total: judge.weighted_total || null,
    regression_flags: judge.regression_flags || [],
    prompt_fix_suggestions: judge.prompt_fix_suggestions || []
  });

  console.log('[Code Format Outputs] emitting version=' + nextVersion + ' score=' + (judge.weighted_total || 'n/a') + (regressionWarning ? ' [REGRESSION]' : '') + (missing.length > 0 ? ' [GUARDRAIL]' : ''));
  return [{ json: {
    call_log: callLog,
    analysis_report: analysisReport,
    prompt_version: promptVersion,
    revised_prompt: promptVersion.prompt
  }}];
} catch (error) {
  return [{ json: { error: String(error), raw_call: $node['Code Prepare Inputs'].json.call || {} } }];
}

